// ── Draggable product images ──────────────────────────────────────
function initDraggable() {
  const SCALE = 1.14;
  const MAX_X = 110;
  const MAX_Y = 80;
  const states = [];

  const getStageScale = () => {
    try {
      const canvas = document.querySelector('deck-stage')
        ?.shadowRoot?.querySelector('.canvas');
      if (!canvas) return 1;
      return new DOMMatrix(getComputedStyle(canvas).transform).a || 1;
    } catch(e) { return 1; }
  };

  document.querySelectorAll('.product-visual').forEach(container => {
    const img = container.querySelector('img');
    if (!img) return;

    const state = { container, img, posX: 0, posY: 0, active: false, lastX: 0, lastY: 0 };
    states.push(state);

    const update = () => {
      img.style.transform = `translate(${state.posX}px, ${state.posY}px) scale(${SCALE}) translateY(-2%)`;
    };
    state.update = update;
    update();

    container.addEventListener('mousedown', e => {
      if (e.button !== 0) return;
      state.active = true;
      state.lastX = e.clientX;
      state.lastY = e.clientY;
      container.classList.add('is-dragging');
      e.preventDefault();
    });

    container.addEventListener('touchstart', e => {
      state.active = true;
      state.lastX = e.touches[0].clientX;
      state.lastY = e.touches[0].clientY;
      e.preventDefault();
    }, { passive: false });
  });

  window.addEventListener('mousemove', e => {
    states.forEach(s => {
      if (!s.active) return;
      const ss = getStageScale();
      s.posX = Math.max(-MAX_X, Math.min(MAX_X, s.posX + (e.clientX - s.lastX) / ss));
      s.posY = Math.max(-MAX_Y, Math.min(MAX_Y, s.posY + (e.clientY - s.lastY) / ss));
      s.lastX = e.clientX;
      s.lastY = e.clientY;
      s.update();
    });
  });

  window.addEventListener('touchmove', e => {
    states.forEach(s => {
      if (!s.active) return;
      const ss = getStageScale();
      s.posX = Math.max(-MAX_X, Math.min(MAX_X, s.posX + (e.touches[0].clientX - s.lastX) / ss));
      s.posY = Math.max(-MAX_Y, Math.min(MAX_Y, s.posY + (e.touches[0].clientY - s.lastY) / ss));
      s.lastX = e.touches[0].clientX;
      s.lastY = e.touches[0].clientY;
      s.update();
    });
  }, { passive: false });

  window.addEventListener('mouseup', () => {
    states.forEach(s => {
      s.active = false;
      s.container.classList.remove('is-dragging');
    });
  });
  window.addEventListener('touchend', () => {
    states.forEach(s => { s.active = false; });
  });

  // Reset position when slide changes
  document.querySelector('deck-stage')?.addEventListener('slidechange', () => {
    states.forEach(s => {
      s.posX = 0; s.posY = 0;
      s.update();
    });
  });
}

